var e=[{id:`L5_1`,type:`dialog`,speaker:`OPR_NPC_NULL_NULL`,text:{KOREA:`다이브 아웃 완료.`,JPN:`ダイブアウト完了。`,ENG:`Dive-out completed.`,TWN:`躍出完畢。`},stage:{bg:`PROLOGUE_02`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:`OPR_NPC_NULL_NULL`,text:{KOREA:`매복에 대비해 즉시 위상 장벽을 전개합니다.`,JPN:`待ち伏せに備えてただちに位相防壁を展開します。`,ENG:`Casting a phase barrier in case of possible ambush...`,TWN:`小心埋伏，立刻打開屏障。`},stage:{bg:`PROLOGUE_02`,slots:{L:null,C:null,R:null}}},{id:`L7_1`,type:`dialog`,speaker:`LEEJIN_ALPHA_NULL_NULL`,text:{KOREA:`포드가 추락한 위치를 확인하세요. 파악되는 대로 단거리 도약을 통해 진입합니다.`,JPN:`ポッドが墜落した位置を確認してください。把握でき次第、短距離跳躍で進入します。`,ENG:`Check the pod's landing location. We'll make a short leap to get there.`,TWN:`請確認艙降落的位置，確認到後立刻透過短距離跳躍進入。`},stage:{bg:`PROLOGUE_02`,slots:{L:null,C:{char_id:`LEEJIN_ALPHA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`JIA_ALPHA_NULL_NULL`,text:{KOREA:`여기가 서브스톰이군요.`,JPN:`ここがサブストームですね。`,ENG:`This is Substorm.`,TWN:`這裡就是次級風暴嗎？！`},stage:{bg:`PROLOGUE_02`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`JIA_ALPHA_NULL_NULL`,text:{KOREA:`이렇게 이면세계 깊숙한 곳에서 사람들이 살고 있다니…… 신기해요.`,JPN:`こんな裏世界の奥深いところに人が住んでいるとは……不思議ですね。`,ENG:`I can't believe some people live in the depths of the Counterside.`,TWN:`竟然有人居住在異界這麼深的地方……好奇妙。`},stage:{bg:`PROLOGUE_02`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`JIA_ALPHA_NULL_NULL`,text:{KOREA:`하늘도 우주 같아서, 꼭 달기지에 온 기분이에요.`,JPN:`空も宇宙みたいですし、まるで月面基地に来ている気分です。`,ENG:`The sky above looks like outer space. I feel like I'm on a moon base.`,TWN:`天空長得好像宇宙，感覺就像來到月亮基地一樣。`},stage:{bg:`PROLOGUE_02`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`LEEJIN_ALPHA_NULL_NULL`,text:{KOREA:`보이는 것만큼 아름답기만 한 곳은 아닙니다, 아가씨.`,JPN:`見た目ほど美しい場所ではありませんよ、お嬢様。`,ENG:`This place is not as beautiful as it looks, Miss Jia.`,TWN:`小姐，這裡並非像妳眼睛看到的那般美好。`},stage:{bg:`PROLOGUE_02`,slots:{L:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`LEEJIN_ALPHA_NULL_NULL`,face:`UNIT_DESPAIR`}}}},{id:`L15_1`,type:`dialog`,speaker:`LEEJIN_ALPHA_NULL_NULL`,text:{KOREA:`이면세계에 이렇게 거대한 시설을 세우는 동안, 그들에게 붙잡힌 기술자들이 수없이 희생되어야 했으니까요. `,JPN:`裏世界にこんなに巨大な施設を建てる間にも、
彼らに囚われた技術者が数え切れないほど犠牲になりましたから。`,ENG:`The pirates sacrificed countless technicians to build such a big facility on the Counterside. `,TWN:`要在異界裡進行如此浩大的工程，也就表示被犧牲的研究人員難以計數。`},stage:{bg:`PROLOGUE_02`,slots:{L:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`LEEJIN_ALPHA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L16_1`,type:`dialog`,speaker:`JIA_ALPHA_NULL_NULL`,text:{KOREA:`그렇군요……`,JPN:`そうですね……`,ENG:`I see...`,TWN:`原來是這樣……`},stage:{bg:`PROLOGUE_02`,slots:{L:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`LEEJIN_ALPHA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L17_1`,type:`dialog`,speaker:`JIA_ALPHA_NULL_NULL`,text:{KOREA:`그럼 왜 그 해적 분들은 이런 곳에 건물을 짓고 사는 건가요?`,JPN:`ところで海賊たちはなぜこんな所に暮らしているんですか？`,ENG:`But why did the pirates decide to build their home in a place like this?`,TWN:`但那些海盜為什麼要在這種地方蓋建築物，住在這裡呢？`},stage:{bg:`PROLOGUE_02`,slots:{L:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_DESPAIR`},C:null,R:{char_id:`LEEJIN_ALPHA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L18_1`,type:`dialog`,speaker:`LEEJIN_ALPHA_NULL_NULL`,text:{KOREA:`관리국의 감시를 피해 이면세계의 유물을 파헤치고 연구하기 위해서입니다.`,JPN:`管理局の監視を避けながら裏世界の遺物を掘り起こして研究するためです。`,ENG:`To excavate and study Artifacts on the Counterside without detection from the Administration.`,TWN:`他們想躲避管理局的監視，挖掘異界的遺物進行研究。`},stage:{bg:`PROLOGUE_02`,slots:{L:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_DESPAIR`},C:null,R:{char_id:`LEEJIN_ALPHA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L19_1`,type:`dialog`,speaker:`LEEJIN_ALPHA_NULL_NULL`,text:{KOREA:`이런 고심도일수록 더 진귀한 것들이 발견되니까요.`,JPN:`ここのように高深度になるほど、より珍しいものが発見されますから。`,ENG:`The deeper you go, the more valuable things you can find.`,TWN:`因為越深的地方，發現的東西就越稀有。`},stage:{bg:`PROLOGUE_02`,slots:{L:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_DESPAIR`},C:null,R:{char_id:`LEEJIN_ALPHA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L23_1`,type:`dialog`,speaker:`COLLECTOR_NPC_NULL_NULL`,text:{KOREA:`빨리 움직여! 머리를 새로운 몸체에 연결하는 거다! 시뮬레이션은 생략해!`,JPN:`さっさと動け！　頭部を新しい胴体に繋げるんだ！　シミュレーションは省略しろ！`,ENG:`Get moving! Connect the head to the new body! Skip simulations!`,TWN:`動作快！將頭連接到新的主體！模擬就省了！`},stage:{bg:`HANGAR`,slots:{L:null,C:{char_id:`COLLECTOR_NPC_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`ENGINEER_SCAVENGER_C_NULL`,text:{KOREA:`몸체의 가동 점검 완료! 머리 동기화 수준 81%!`,JPN:`胴体の稼働点検完了！　頭部同期化レベル81％！`,ENG:`Body's mobility checked! Head synch level: 81%!`,TWN:`主體的啟動維護完成！頭重置程度 81%！`},stage:{bg:`HANGAR`,slots:{L:{char_id:`ENGINEER_SCAVENGER_C_NULL`,face:`UNIT_IDLE`},C:null,R:null}}}];export{e as default};